const DARK_MODE_KEY="coreadmin-dark-mode";function isDarkMode(){const savedMode=localStorage.getItem(DARK_MODE_KEY);if(savedMode!==null){return savedMode==="dark"}return window.matchMedia("(prefers-color-scheme: dark)").matches}function applyDarkMode(isDark){const html=document.documentElement;const darkModeToggle=document.getElementById("darkModeToggle");if(isDark){html.classList.add("dark");localStorage.setItem(DARK_MODE_KEY,"dark")}else{html.classList.remove("dark");localStorage.setItem(DARK_MODE_KEY,"light")}if(darkModeToggle){const moonIcon=darkModeToggle.querySelector(".fa-moon");const sunIcon=darkModeToggle.querySelector(".fa-sun");if(moonIcon&&sunIcon){moonIcon.classList.toggle("hidden",isDark);sunIcon.classList.toggle("hidden",!isDark)}}}function toggleDarkMode(){const isDark=!isDarkMode();applyDarkMode(isDark)}function initDarkMode(){applyDarkMode(isDarkMode());const darkModeToggle=document.getElementById("darkModeToggle");if(darkModeToggle){darkModeToggle.addEventListener("click",toggleDarkMode)}window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",e=>{if(localStorage.getItem(DARK_MODE_KEY)===null){applyDarkMode(e.matches)}})}const sidebar=document.getElementById("sidebar");const sidebarOverlay=document.getElementById("sidebarOverlay");const openSidebarBtn=document.getElementById("openSidebar");const closeSidebarBtn=document.getElementById("closeSidebar");function openSidebar(){if(sidebar){sidebar.classList.remove("-translate-x-full");sidebarOverlay.classList.remove("hidden");document.body.style.overflow="hidden"}}function closeSidebar(){if(sidebar){sidebar.classList.add("-translate-x-full");sidebarOverlay.classList.add("hidden");document.body.style.overflow=""}}function initSidebar(){if(openSidebarBtn){openSidebarBtn.addEventListener("click",openSidebar)}if(closeSidebarBtn){closeSidebarBtn.addEventListener("click",closeSidebar)}if(sidebarOverlay){sidebarOverlay.addEventListener("click",closeSidebar)}document.addEventListener("keydown",e=>{if(e.key==="Escape"){closeSidebar();closeModal()}})}const modal=document.getElementById("modal");function openModal(){if(modal){modal.classList.add("active");document.body.style.overflow="hidden"}}function closeModal(){if(modal){modal.classList.remove("active");document.body.style.overflow=""}}function initModal(){if(modal){modal.addEventListener("click",e=>{if(e.target===modal){closeModal()}})}}function switchTab(btn,tabId){document.querySelectorAll(".tab-btn").forEach(tab=>tab.classList.remove("active"));btn.classList.add("active");document.querySelectorAll(".tab-content").forEach(content=>content.classList.remove("active"));const tabContent=document.getElementById(tabId);if(tabContent){tabContent.classList.add("active")}}function togglePassword(inputId){const input=document.getElementById(inputId);const icon=document.getElementById(inputId+"-icon");if(input&&icon){if(input.type==="password"){input.type="text";icon.classList.remove("fa-eye");icon.classList.add("fa-eye-slash")}else{input.type="password";icon.classList.remove("fa-eye-slash");icon.classList.add("fa-eye")}}}function initToggleSwitches(){document.querySelectorAll(".toggle-switch").forEach(toggle=>{toggle.addEventListener("click",function(){this.classList.toggle("active")})})}function initCheckboxes(){document.querySelectorAll(".custom-checkbox").forEach(checkbox=>{checkbox.addEventListener("click",function(){this.classList.toggle("checked")})})}function initRadioButtons(){document.querySelectorAll(".custom-radio").forEach(radio=>{radio.addEventListener("click",function(){const groupClass=Array.from(this.parentElement.classList).find(cls=>cls.includes("-radio"));if(groupClass){const groupName=groupClass.replace("-radio","");document.querySelectorAll("."+groupName).forEach(r=>r.classList.remove("checked"));this.classList.add("checked")}})})}function initNotifications(){document.querySelectorAll(".notification-item").forEach(item=>{item.addEventListener("click",function(){this.classList.remove("unread")})})}let currentDate=new Date;let currentMonth=currentDate.getMonth();let currentYear=currentDate.getFullYear();const monthNames=["January","February","March","April","May","June","July","August","September","October","November","December"];const events=[5,12,15,22,28];function generateCalendar(month,year){const firstDay=new Date(year,month,1).getDay();const daysInMonth=new Date(year,month+1,0).getDate();const today=(new Date).getDate();const isCurrentMonth=(new Date).getMonth()===month&&(new Date).getFullYear()===year;const calendarDays=document.getElementById("calendarDays");if(!calendarDays)return;let calendarHTML="";for(let i=0;i<firstDay;i++){calendarHTML+='<div class="calendar-day empty p-2 text-center text-sm text-secondary"></div>'}for(let day=1;day<=daysInMonth;day++){const isToday=isCurrentMonth&&day===today;const hasEvent=events.includes(day);const classes=`calendar-day p-2 text-center text-sm text-dark rounded-lg ${isToday?"today":""} ${hasEvent?"has-event":""}`;calendarHTML+=`<div class="${classes}">${day}</div>`}calendarDays.innerHTML=calendarHTML;const currentMonthEl=document.getElementById("currentMonth");if(currentMonthEl){currentMonthEl.textContent=`${monthNames[month]} ${year}`}}function changeMonth(delta){currentMonth+=delta;if(currentMonth>11){currentMonth=0;currentYear++}else if(currentMonth<0){currentMonth=11;currentYear--}generateCalendar(currentMonth,currentYear)}function initCalendar(){generateCalendar(currentMonth,currentYear)}function validateEmail(email){const emailRegex=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;return emailRegex.test(email)}function validatePassword(password){return password.length>=8}function showInputError(input){if(input){input.classList.add("input-error")}}function clearInputError(input){if(input){input.classList.remove("input-error")}}function formatDate(date){const options={year:"numeric",month:"short",day:"numeric"};return date.toLocaleDateString("en-US",options)}function formatNumber(num){return num.toString().replace(/\B(?=(\d{3})+(?!\d))/g,",")}function debounce(func,wait){let timeout;return function executedFunction(...args){const later=()=>{clearTimeout(timeout);func(...args)};clearTimeout(timeout);timeout=setTimeout(later,wait)}}document.addEventListener("DOMContentLoaded",function(){initDarkMode();initSidebar();initModal();initToggleSwitches();initCheckboxes();initRadioButtons();initNotifications();if(document.getElementById("calendarDays")){initCalendar()}console.log("TailAdmin initialized successfully")});function initLoginPage(){const loginForm=document.getElementById("loginForm");if(loginForm){loginForm.addEventListener("submit",function(e){e.preventDefault();const email=document.getElementById("email");const password=document.getElementById("password");let isValid=true;if(!validateEmail(email.value)){showInputError(email);isValid=false}else{clearInputError(email)}if(!validatePassword(password.value)){showInputError(password);isValid=false}else{clearInputError(password)}if(isValid){alert("Login successful!")}});const emailInput=document.getElementById("email");const passwordInput=document.getElementById("password");if(emailInput){emailInput.addEventListener("input",function(){clearInputError(this)})}if(passwordInput){passwordInput.addEventListener("input",function(){clearInputError(this)})}}}function initRegisterPage(){const registerForm=document.getElementById("registerForm");if(registerForm){registerForm.addEventListener("submit",function(e){e.preventDefault();const fullName=document.getElementById("fullName");const email=document.getElementById("email");const password=document.getElementById("password");const confirmPassword=document.getElementById("confirmPassword");const terms=document.getElementById("terms");let isValid=true;if(fullName.value.trim().length<2){showInputError(fullName);isValid=false}else{clearInputError(fullName)}if(!validateEmail(email.value)){showInputError(email);isValid=false}else{clearInputError(email)}if(!validatePassword(password.value)){showInputError(password);isValid=false}else{clearInputError(password)}if(password.value!==confirmPassword.value){showInputError(confirmPassword);isValid=false}else{clearInputError(confirmPassword)}if(!terms.checked){showInputError(terms);isValid=false}else{clearInputError(terms)}if(isValid){alert("Registration successful!")}});["fullName","email","password","confirmPassword"].forEach(id=>{const input=document.getElementById(id);if(input){input.addEventListener("input",function(){clearInputError(this)})}});const termsCheckbox=document.getElementById("terms");if(termsCheckbox){termsCheckbox.addEventListener("change",function(){clearInputError(this)})}}}function initForgotPasswordPage(){const forgotPasswordForm=document.getElementById("forgotPasswordForm");if(forgotPasswordForm){forgotPasswordForm.addEventListener("submit",function(e){e.preventDefault();const email=document.getElementById("email");let isValid=true;if(!validateEmail(email.value)){showInputError(email);isValid=false}else{clearInputError(email)}if(isValid){const successMessage=document.getElementById("successMessage");if(successMessage){successMessage.classList.remove("hidden")}forgotPasswordForm.reset()}});const emailInput=document.getElementById("email");if(emailInput){emailInput.addEventListener("input",function(){clearInputError(this)})}}}function initProfilePage(){const profileForm=document.getElementById("profileForm");if(profileForm){profileForm.addEventListener("submit",function(e){e.preventDefault();alert("Profile updated successfully!")})}}function initSettingsPage(){const settingsForm=document.getElementById("settingsForm");if(settingsForm){settingsForm.addEventListener("submit",function(e){e.preventDefault();alert("Settings saved successfully!")})}}window.TailAdmin={openSidebar:openSidebar,closeSidebar:closeSidebar,openModal:openModal,closeModal:closeModal,switchTab:switchTab,togglePassword:togglePassword,changeMonth:changeMonth,validateEmail:validateEmail,validatePassword:validatePassword,showInputError:showInputError,clearInputError:clearInputError,formatDate:formatDate,formatNumber:formatNumber,debounce:debounce};